import "./Expenses.css";
import ExpenseItem from "./ExpenseItem";
import Card from "../UI/Card";
import ExpensesFilter from "../ExpenseFilter/ExpenseFilter";

const Expenses = (props) => {
  const items = props.expenseList;

  const expenseFilterHandler = (year) => {
    console.log(year);
  };
  return (
    <div>
      <Card className="expenses">
        <ExpensesFilter onAddExpenseFilter={expenseFilterHandler} />
        <ExpenseItem
          title={items[0].title}
          date={items[0].date}
          amount={items[0].amount}
        />
        <ExpenseItem
          title={items[1].title}
          date={items[1].date}
          amount={items[1].amount}
        />
        <ExpenseItem
          title={items[2].title}
          date={items[2].date}
          amount={items[2].amount}
        />
        <ExpenseItem
          title={items[3].title}
          date={items[3].date}
          amount={items[3].amount}
        />
      </Card>
    </div>
  );
};

export default Expenses;
